package com.example.socialloginapp

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.util.Log
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.FacebookSdk
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class SocialLoginModule(private val context: Context, private val listener: SocialLoginListener) {

    // Hardcoded OAuth client IDs and secrets - FOR BETA TESTING ONLY
    // WARNING: Storing secrets directly in client-side code is highly insecure
    // and should NEVER be done in a production environment.
    private val FACEBOOK_APP_ID = "123456789012345"
    private val FACEBOOK_APP_SECRET = "abcdef1234567890abcdef1234567890" // This is Facebook App Secret, not directly used by client-side SDK for login
    private val GOOGLE_WEB_CLIENT_ID = "1234-abcdef.apps.googleusercontent.com" // This is typically a web client ID for backend auth
    private val GOOGLE_CLIENT_SECRET = "GOCSpx-AbCdEf123456" // This is Google Client Secret, not directly used by client-side SDK for login

    private val GOOGLE_SIGN_IN_REQUEST_CODE = 9001

    private lateinit var callbackManager: CallbackManager
    private lateinit var googleSignInClient: GoogleSignInClient

    init {
        // Initialize Facebook SDK
        // It's good practice to set Application ID explicitly, though it's also read from AndroidManifest.xml
        FacebookSdk.setApplicationId(FACEBOOK_APP_ID)
        FacebookSdk.sdkInitialize(context.applicationContext)
        callbackManager = CallbackManager.Factory.create()

        // Initialize Google Sign-In
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestProfile()
            // Request ID token for backend authentication. Use the web client ID here.
            .requestIdToken(GOOGLE_WEB_CLIENT_ID)
            .build()
        googleSignInClient = GoogleSignIn.getClient(context, gso)

        // Register Facebook login callback
        LoginManager.getInstance().registerCallback(callbackManager, object : FacebookCallback<LoginResult> {
            override fun onSuccess(result: LoginResult) {
                Log.d("SocialLoginModule", "Facebook login success: ${result.accessToken.token}")
                listener.onFacebookLoginSuccess(result.accessToken.token, result.accessToken.userId)
            }

            override fun onCancel() {
                Log.d("SocialLoginModule", "Facebook login cancelled")
                listener.onLoginCancelled("Facebook login cancelled")
            }

            override fun onError(error: FacebookException) {
                Log.e("SocialLoginModule", "Facebook login error: ${error.message}", error)
                listener.onLoginError("Facebook login failed: ${error.message}")
            }
        })
    }

    fun facebookLogin(activity: Activity) {
        LoginManager.getInstance().logInWithReadPermissions(activity, listOf("public_profile", "email"))
    }

    fun googleLogin(activity: Activity) {
        val signInIntent = googleSignInClient.signIn
        activity.startActivityForResult(signInIntent, GOOGLE_SIGN_IN_REQUEST_CODE)
    }

    /**
     * This method must be called from the host Activity's onActivityResult to
     * pass the result back to the SDKs.
     */
    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        // Pass the activity result to the Facebook SDK.
        callbackManager.onActivityResult(requestCode, resultCode, data)

        // Handle Google Sign-In result
        if (requestCode == GOOGLE_SIGN_IN_REQUEST_CODE) {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            handleGoogleSignInResult(task)
        }
    }

    private fun handleGoogleSignInResult(completedTask: Task<GoogleSignInAccount>) {
        try {
            val account = completedTask.getResult(ApiException::class.java)
            Log.d("SocialLoginModule", "Google login success: ID=${account.id}, Email=${account.email}, Name=${account.displayName}, ID Token=${account.idToken}")
            listener.onGoogleLoginSuccess(account.idToken, account.id, account.email, account.displayName)
        } catch (e: ApiException) {
            Log.e("SocialLoginModule", "Google sign in failed code=${e.statusCode}: ${e.message}", e)
            listener.onLoginError("Google login failed: ${e.statusCode} - ${e.message}")
        }
    }

    interface SocialLoginListener {
        fun onFacebookLoginSuccess(accessToken: String, userId: String)
        fun onGoogleLoginSuccess(idToken: String?, userId: String?, email: String?, displayName: String?)
        fun onLoginCancelled(message: String)
        fun onLoginError(errorMessage: String)
    }
}

MainActivity.kt

package com.example.socialloginapp

import android.content.Intent
import android.os.Bundle
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class MainActivity : AppCompatActivity(), SocialLoginModule.SocialLoginListener {

    private lateinit var socialLoginModule: SocialLoginModule

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        socialLoginModule = SocialLoginModule(this, this)

        findViewById<Button>(R.id.facebook_login_button).setOnClickListener {
            socialLoginModule.facebookLogin(this)
        }

        findViewById<Button>(R.id.google_login_button).setOnClickListener {
            socialLoginModule.googleLogin(this)
        }
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        // Delegate onActivityResult to the SocialLoginModule
        socialLoginModule.onActivityResult(requestCode, resultCode, data)
    }

    // SocialLoginListener implementations
    override fun onFacebookLoginSuccess(accessToken: String, userId: String) {
        Toast.makeText(this, "Facebook Login Success! User ID: $userId", Toast.LENGTH_LONG).show()
        // Here you would typically send the accessToken to your backend for verification
        Log.d("MainActivity", "Facebook Access Token: $accessToken")
    }

    override fun onGoogleLoginSuccess(idToken: String?, userId: String?, email: String?, displayName: String?) {
        Toast.makeText(this, "Google Login Success! Email: $email", Toast.LENGTH_LONG).show()
        // Here you would typically send the idToken to your backend for verification
        Log.d("MainActivity", "Google ID Token: $idToken")
        Log.d("MainActivity", "Google User ID: $userId")
        Log.d("MainActivity", "Google Email: $email")
        Log.d("MainActivity", "Google Display Name: $displayName")
    }

    override fun onLoginCancelled(message: String) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
    }

    override fun onLoginError(errorMessage: String) {
        Toast.makeText(this, "Login Error: $errorMessage", Toast.LENGTH_LONG).show()
    }
}